import { useMemo } from 'react';
import { CAB_TYPES } from '../data/mockData';

const SURGE_MULTIPLIER = 1.2;
const GST_RATE = 0.05;
const FIXED_DISTANCE_KM = 23.5; // mock distance for demo

export function useFare(cabId, promoDiscount = 0) {
  return useMemo(() => {
    const cab = CAB_TYPES.find(c => c.id === cabId) || CAB_TYPES[0];
    const km = FIXED_DISTANCE_KM;
    const baseFare = cab.baseFare;
    const distFare = Math.round(km * cab.ratePerKm);
    const surge    = Math.round(distFare * (SURGE_MULTIPLIER - 1));
    const subtotal = baseFare + distFare + surge;
    const gst      = Math.round(subtotal * GST_RATE);
    const gross    = subtotal + gst;
    const discount = Math.min(promoDiscount, gross);
    const total    = gross - discount;

    return {
      km,
      baseFare,
      distFare,
      surge,
      gst,
      gross,
      discount,
      total,
      surgeMultiplier: SURGE_MULTIPLIER,
    };
  }, [cabId, promoDiscount]);
}

export function formatCurrency(amount) {
  return '₹' + amount.toLocaleString('en-IN');
}
